// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/**
 * 用户直接调用、纯链上：报名锦标赛/创建房间时扣费并燃烧，无 operator、无后端代执行。
 */
interface IERC20Burnable {
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function burn(uint256 amount) external;
}

contract AllinGame {
    IERC20Burnable public immutable token;
    address public owner;

    uint256 public tournamentFee = 100000 * 1e18;   // 10 万代币（18 decimals）
    uint256 public roomCreationFee = 10000 * 1e18;  // 1 万代币

    event TournamentRegistered(address indexed user, uint256 fee);
    event RoomCreated(address indexed user, uint256 fee);

    constructor(address tokenAddress) {
        token = IERC20Burnable(tokenAddress);
        owner = msg.sender;
    }

    /// @notice 用户报名锦标赛：先转费到本合约再燃烧
    function registerTournament() external {
        token.transferFrom(msg.sender, address(this), tournamentFee);
        token.burn(tournamentFee);
        emit TournamentRegistered(msg.sender, tournamentFee);
    }

    /// @notice 用户创建房间：先转费到本合约再燃烧
    function createRoom() external {
        token.transferFrom(msg.sender, address(this), roomCreationFee);
        token.burn(roomCreationFee);
        emit RoomCreated(msg.sender, roomCreationFee);
    }

    /// @notice owner 可调整费用
    function setFees(uint256 _tournamentFee, uint256 _roomFee) external {
        require(msg.sender == owner, "ONLY_OWNER");
        tournamentFee = _tournamentFee;
        roomCreationFee = _roomFee;
    }
}

